import React, { useState, useEffect } from 'react';
import Hero from '../Hero/Hero';
import { CinemaCard } from './CinemaCard';
import ModalForm from './ModalForm';
import './CinemaManagement.css';

const CinemaManagement = () => {
  const [cinemas, setCinemas] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [editingCinema, setEditingCinema] = useState(null);
  const [notification, setNotification] = useState({ show: false, message: '', type: '' });

  const fetchCinemas = async () => {
    try {
      setLoading(true);
      const response = await fetch('http://localhost:5000/api/cinemas');
      const data = await response.json();
      
      if (data.success) {
        setCinemas(data.data);
      } else {
        console.error('Error fetching cinemas:', data.message);
        showNotification('Error fetching cinemas', 'error');
      }
    } catch (error) {
      console.error('Error fetching cinemas:', error);
      showNotification('Error fetching cinemas', 'error');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchCinemas();
  }, []);

  const showNotification = (message, type) => {
    setNotification({ show: true, message, type });
    setTimeout(() => {
      setNotification({ show: false, message: '', type: '' });
    }, 3000);
  };

  const handleCreateNew = () => {
    setEditingCinema(null);
    setShowModal(true);
  };

  const handleEdit = (cinema) => {
    setEditingCinema(cinema);
    setShowModal(true);
  };

  const handleDelete = async (cinemaId) => {
    if (window.confirm('Are you sure you want to delete this cinema?')) {
      try {
        const response = await fetch(`http://localhost:5000/api/cinemas/${cinemaId}`, {
          method: 'DELETE',
        });
        
        const data = await response.json();
        
        if (data.success) {
          setCinemas(cinemas.filter(cinema => cinema._id !== cinemaId));
          showNotification('Cinema deleted successfully', 'success');
        } else {
          showNotification('Error deleting cinema', 'error');
        }
      } catch (error) {
        console.error('Error deleting cinema:', error);
        showNotification('Error deleting cinema', 'error');
      }
    }
  };

  const handleModalClose = () => {
    setShowModal(false);
    setEditingCinema(null);
  };

  const handleModalSubmit = async (cinemaData) => {
    try {
      const url = editingCinema 
        ? `http://localhost:5000/api/cinemas/${editingCinema._id}`
        : 'http://localhost:5000/api/cinemas';
      
      const method = editingCinema ? 'PUT' : 'POST';
      
      const response = await fetch(url, {
        method,
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(cinemaData),
      });
      
      const data = await response.json();
      
      if (data.success) {
        if (editingCinema) {
          setCinemas(cinemas.map(cinema => 
            cinema._id === editingCinema._id ? data.data : cinema
          ));
          showNotification('Cinema updated successfully', 'success');
        } else {
          setCinemas([...cinemas, data.data]);
          showNotification('Cinema created successfully', 'success');
        }
        handleModalClose();
      } else {
        showNotification(data.message || 'Error saving cinema', 'error');
      }
    } catch (error) {
      console.error('Error saving cinema:', error);
      showNotification('Error saving cinema', 'error');
    }
  };

  if (loading) {
    return (
      <div className="cinema-management">
        <Hero 
          title="CINEMA"
          subtitle="MANAGEMENT"
          backgroundVideo="https://www.youtube.com/watch?v=f1Ntb6hJDQU"
          backgroundImage="https://images.unsplash.com/photo-1489599808426-7b0a4a0a0a0a?ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D&auto=format&fit=crop&w=2070&q=80"
          scrollTarget="#content"
          typingStrings={["MANAGE", "CONTROL", "ADMIN"]}
        />
        <div className="loading-container">
          <div className="loading-spinner"></div>
          <p>Loading cinemas...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="cinema-management">
      <Hero 
        title="CINEMA"
        subtitle="MANAGEMENT"
        backgroundVideo="https://www.youtube.com/watch?v=f1Ntb6hJDQU"
        backgroundImage="https://images.unsplash.com/photo-1489599808426-7b0a4a0a0a0a?ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D&auto=format&fit=crop&w=2070&q=80"
        scrollTarget="#content"
        typingStrings={["MANAGE", "CONTROL", "ADMIN"]}
      />
      <div id="content" className="content-section">
        <div className="page-header">
          <div className="container">
            <button 
              className="btn btn-primary create-btn"
              onClick={handleCreateNew}
            >
              <i className="fa fa-plus"></i>
              Create New Cinema
            </button>
          </div>
        </div>

        <div className="cinemas-section">
          <div className="container">
            <h2>Cinema Management</h2>
            <p>Manage your cinema locations and movie schedules</p>
            
            {cinemas.length === 0 ? (
              <div className="no-cinemas">
                <i className="fa fa-building-o"></i>
                <h3>No Cinemas Found</h3>
                <p>Start by creating your first cinema location</p>
                <button 
                  className="btn btn-primary"
                  onClick={handleCreateNew}
                >
                  Create Cinema
                </button>
              </div>
            ) : (
              <div className="cinemas-grid">
                {cinemas.map((cinema) => (
                  <CinemaCard
                    key={cinema._id}
                    cinema={cinema}
                    onEdit={handleEdit}
                    onDelete={handleDelete}
                  />
                ))}
              </div>
            )}
          </div>
        </div>
      </div>

      {/* Modal */}
      {showModal && (
        <ModalForm
          cinema={editingCinema}
          onClose={handleModalClose}
          onSubmit={handleModalSubmit}
        />
      )}

      {/* Notification */}
      {notification.show && (
        <div className={`notification ${notification.type}`}>
          <i className={`fa ${notification.type === 'success' ? 'fa-check-circle' : 'fa-exclamation-circle'}`}></i>
          <span>{notification.message}</span>
        </div>
      )}
    </div>
  );
};

export default CinemaManagement;
